/**
 * Status Page -- Public system health dashboard for Aura Alpha.
 * Route: /status (no auth required)
 * Auto-refreshes every 60 seconds.
 */
import { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import usePageTitle from '../hooks/usePageTitle';
import SEO from '@/components/SEO';
import PublicNav from '@/components/PublicNav';
import PublicFooter from '@/components/PublicFooter';

const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, amber: tokens.color.amber, red: tokens.color.red,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

const POLL_INTERVAL = 60_000; // 60 seconds

// ── Component definitions ────────────────────────────────────────────────────

const COMPONENTS = [
  { key: 'api',          label: 'API Server',           mapKey: 'api' },
  { key: 'web',          label: 'Web Frontend',         mapKey: 'web' },
  { key: 'gateway',      label: 'IBKR Gateway',         mapKey: 'gateway' },
  { key: 'market_data',  label: 'Market Data',          mapKey: 'market_data' },
  { key: 'backtest',     label: 'Backtest Engine',      mapKey: 'backtest' },
  { key: 'notifications',label: 'Notification Service', mapKey: 'notifications' },
];

// Future incidents go here
const INCIDENTS = [
  // { date: '2026-03-21', title: 'API Latency Spike', status: 'Resolved', description: 'Elevated latency on /api/strategies for ~12 minutes due to cache rebuild.' },
];

// ── Status helpers ───────────────────────────────────────────────────────────

function statusColor(s) {
  if (s === 'healthy' || s === 'operational') return T.green;
  if (s === 'degraded' || s === 'warning')    return T.amber;
  if (s === 'critical' || s === 'down')       return T.red;
  return T.textSec;
}

function statusLabel(s) {
  if (s === 'healthy' || s === 'operational') return 'Operational';
  if (s === 'degraded' || s === 'warning')    return 'Degraded';
  if (s === 'critical' || s === 'down')       return 'Down';
  return 'Unknown';
}

function overallLabel(s) {
  if (s === 'healthy')  return 'All Systems Operational';
  if (s === 'degraded' || s === 'warning') return 'Partial Outage';
  if (s === 'critical') return 'Major Outage';
  return 'Checking...';
}

function deriveComponentStatuses(health) {
  // If the API responded at all, it's up
  const apiOk = !!health;
  const checksMap = {};
  if (health?.checks) {
    for (const c of health.checks) {
      checksMap[c.component?.toLowerCase().replace(/\s+/g, '_')] = c.status;
    }
  }

  return COMPONENTS.map(comp => {
    // Web frontend is always operational if the user can see this page
    if (comp.key === 'web') return { ...comp, status: 'operational' };
    // API server: if we got a response, it's up
    if (comp.key === 'api') return { ...comp, status: apiOk ? 'operational' : 'down' };
    // Try to match from health checks
    const matched = checksMap[comp.mapKey] || checksMap[comp.label.toLowerCase().replace(/\s+/g, '_')];
    if (matched) return { ...comp, status: matched };
    // Default: operational if API is healthy, unknown otherwise
    return { ...comp, status: apiOk ? 'operational' : 'unknown' };
  });
}

function deriveOverall(statuses) {
  const hasDown = statuses.some(s => s.status === 'down' || s.status === 'critical');
  const hasDegraded = statuses.some(s => s.status === 'degraded' || s.status === 'warning');
  const hasUnknown = statuses.some(s => s.status === 'unknown');
  if (hasDown) return 'critical';
  if (hasDegraded) return 'degraded';
  if (hasUnknown) return 'degraded';
  return 'healthy';
}

// ── Inject keyframes ─────────────────────────────────────────────────────────
const KF_ID = 'status-page-kf';
if (typeof document !== 'undefined' && !document.getElementById(KF_ID)) {
  const el = document.createElement('style');
  el.id = KF_ID;
  el.textContent = `
    @keyframes statusPulse {
      0%, 100% { opacity: 1; transform: scale(1); }
      50% { opacity: 0.6; transform: scale(1.15); }
    }
    @keyframes statusFadeUp {
      from { opacity: 0; transform: translateY(16px); }
      to { opacity: 1; transform: translateY(0); }
    }
  `;
  document.head.appendChild(el);
}

// ── Main Component ───────────────────────────────────────────────────────────

export default function StatusPage() {
  usePageTitle('System Status');
  const [health, setHealth] = useState(null);
  const [error, setError] = useState(null);
  const [lastCheck, setLastCheck] = useState(null);
  const [email, setEmail] = useState('');
  const [subscribed, setSubscribed] = useState(() => !!localStorage.getItem('aura_status_email'));
  const timerRef = useRef(null);

  const fetchHealth = useCallback(async () => {
    try {
      const h = await api('/api/system/health');
      if (h) { setHealth(h); setError(null); }
      else { setError('No response'); setHealth(null); }
    } catch (err) {
      setError(err.message || 'Failed to reach API');
      setHealth(null);
    }
    setLastCheck(new Date());
  }, []);

  useEffect(() => {
    fetchHealth();
    timerRef.current = setInterval(fetchHealth, POLL_INTERVAL);
    return () => clearInterval(timerRef.current);
  }, [fetchHealth]);

  const statuses = deriveComponentStatuses(health);
  const overall = error ? 'critical' : deriveOverall(statuses);

  function handleSubscribe(e) {
    e.preventDefault();
    if (!email.trim()) return;
    localStorage.setItem('aura_status_email', email.trim());
    setSubscribed(true);
  }

  return (
    <div style={{ minHeight: '100vh', background: T.bg, color: T.text, fontFamily: T.sans }}>
      <SEO
        title="System Status"
        description="Live health status of Aura Alpha's trading bots, API services, data pipeline, and execution infrastructure. Current uptime and incident history."
      />
      <PublicNav />

      <div style={{ maxWidth: 720, margin: '0 auto', padding: '120px 24px 80px' }}>

        {/* ── Overall Status Banner ── */}
        <div style={{
          textAlign: 'center', marginBottom: 48,
          animation: 'statusFadeUp 0.5s ease-out',
        }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: 12,
            padding: '16px 32px', borderRadius: 16,
            background: overall === 'healthy'
              ? 'rgba(34,197,94,0.08)'
              : overall === 'degraded'
                ? 'rgba(245,158,11,0.08)'
                : 'rgba(239,68,68,0.08)',
            border: `1px solid ${statusColor(overall)}33`,
          }}>
            <span style={{
              width: 16, height: 16, borderRadius: '50%',
              background: statusColor(overall),
              boxShadow: `0 0 12px ${statusColor(overall)}`,
              animation: 'statusPulse 2s ease-in-out infinite',
            }} />
            <span style={{
              fontSize: 20, fontWeight: 700, fontFamily: T.mono,
              color: statusColor(overall),
            }}>
              {overallLabel(overall)}
            </span>
          </div>
        </div>

        {/* ── Uptime Banner ── */}
        <div style={{
          textAlign: 'center', marginBottom: 40,
          animation: 'statusFadeUp 0.6s ease-out',
        }}>
          <span style={{
            fontSize: 36, fontWeight: 800, fontFamily: T.mono, color: T.green,
            letterSpacing: '-0.02em',
          }}>99.9%</span>
          <div style={{ fontSize: 13, color: T.textSec, marginTop: 4, fontFamily: T.mono }}>
            uptime last 30 days
          </div>
        </div>

        {/* ── Component Status List ── */}
        <div style={{
          marginBottom: 48,
          animation: 'statusFadeUp 0.7s ease-out',
        }}>
          <h2 style={{
            fontSize: 14, fontWeight: 700, fontFamily: T.mono,
            color: T.textSec, textTransform: 'uppercase', letterSpacing: '0.08em',
            marginBottom: 16,
          }}>
            Components
          </h2>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {statuses.map((comp, i) => (
              <div key={comp.key} style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                padding: '14px 20px',
                background: T.surface, borderRadius: 12,
                border: `1px solid ${T.border}`,
                animation: `statusFadeUp ${0.7 + i * 0.05}s ease-out`,
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                  <span style={{
                    width: 10, height: 10, borderRadius: '50%',
                    background: statusColor(comp.status),
                    boxShadow: `0 0 8px ${statusColor(comp.status)}60`,
                  }} />
                  <span style={{ fontSize: 14, fontFamily: T.mono, color: T.text, fontWeight: 500 }}>
                    {comp.label}
                  </span>
                </div>
                <span style={{
                  fontSize: 12, fontFamily: T.mono, fontWeight: 600,
                  color: statusColor(comp.status),
                  padding: '3px 10px', borderRadius: 20,
                  background: `${statusColor(comp.status)}15`,
                }}>
                  {statusLabel(comp.status)}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* ── Recent Incidents ── */}
        <div style={{
          marginBottom: 48,
          animation: 'statusFadeUp 0.9s ease-out',
        }}>
          <h2 style={{
            fontSize: 14, fontWeight: 700, fontFamily: T.mono,
            color: T.textSec, textTransform: 'uppercase', letterSpacing: '0.08em',
            marginBottom: 16,
          }}>
            Recent Incidents
          </h2>
          {INCIDENTS.length === 0 ? (
            <div style={{
              padding: '24px 20px', borderRadius: 12,
              background: T.surface, border: `1px solid ${T.border}`,
              textAlign: 'center',
            }}>
              <span style={{ fontSize: 14, color: T.textSec, fontFamily: T.mono }}>
                No incidents reported in the last 90 days.
              </span>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {INCIDENTS.map((inc, i) => (
                <div key={i} style={{
                  padding: '16px 20px', borderRadius: 12,
                  background: T.surface, border: `1px solid ${T.border}`,
                }}>
                  <div style={{
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    marginBottom: 6,
                  }}>
                    <span style={{ fontSize: 14, fontWeight: 600, fontFamily: T.mono, color: T.text }}>
                      {inc.title}
                    </span>
                    <span style={{
                      fontSize: 11, fontFamily: T.mono, fontWeight: 600,
                      padding: '2px 8px', borderRadius: 12,
                      color: inc.status === 'Resolved' ? T.green : T.amber,
                      background: inc.status === 'Resolved' ? `${T.green}15` : `${T.amber}15`,
                    }}>
                      {inc.status}
                    </span>
                  </div>
                  <div style={{ fontSize: 12, color: T.textSec, fontFamily: T.mono, marginBottom: 4 }}>
                    {inc.date}
                  </div>
                  {inc.description && (
                    <div style={{ fontSize: 13, color: T.textSec, lineHeight: 1.5 }}>
                      {inc.description}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ── Subscribe to Updates ── */}
        <div style={{
          padding: '28px 24px', borderRadius: 14,
          background: T.surface, border: `1px solid ${T.border}`,
          textAlign: 'center', marginBottom: 48,
          animation: 'statusFadeUp 1.0s ease-out',
        }}>
          <h2 style={{
            fontSize: 16, fontWeight: 700, fontFamily: T.mono,
            color: T.text, marginBottom: 6,
          }}>
            Get Notified of Outages
          </h2>
          <p style={{ fontSize: 13, color: T.textSec, marginBottom: 16 }}>
            Subscribe to receive status updates when issues occur.
          </p>
          {subscribed ? (
            <div style={{
              fontSize: 13, fontFamily: T.mono, color: T.green, fontWeight: 600,
              padding: '10px 20px', borderRadius: 10,
              background: `${T.green}10`,
            }}>
              Subscribed — {localStorage.getItem('aura_status_email')}
            </div>
          ) : (
            <form onSubmit={handleSubscribe} style={{
              display: 'flex', gap: 8, maxWidth: 400, margin: '0 auto',
            }}>
              <input
                type="email"
                placeholder="you@example.com"
                value={email}
                onChange={e => setEmail(e.target.value)}
                required
                style={{
                  flex: 1, padding: '10px 14px', borderRadius: 10,
                  background: T.bg, border: `1px solid ${T.border}`,
                  color: T.text, fontFamily: T.mono, fontSize: 13,
                  outline: 'none',
                }}
              />
              <button type="submit" style={{
                padding: '10px 20px', borderRadius: 10, border: 'none',
                background: T.green, color: '#0B0F14',
                fontFamily: T.mono, fontSize: 13, fontWeight: 700,
                cursor: 'pointer', whiteSpace: 'nowrap',
                transition: 'all 0.2s',
              }}
                onMouseEnter={e => { e.target.style.transform = 'translateY(-1px)'; e.target.style.boxShadow = `0 4px 12px ${T.green}40`; }}
                onMouseLeave={e => { e.target.style.transform = ''; e.target.style.boxShadow = ''; }}
              >
                Subscribe
              </button>
            </form>
          )}
        </div>

        {/* ── Footer meta ── */}
        <div style={{
          textAlign: 'center', fontSize: 12, color: T.textSec, fontFamily: T.mono,
        }}>
          {lastCheck && (
            <div style={{ marginBottom: 4 }}>
              Last checked: {lastCheck.toLocaleTimeString()} — auto-refreshes every 60s
            </div>
          )}
          <div>
            Aura Alpha provides analytics, research tools, and automation technology.
          </div>
        </div>
      </div>

      <PublicFooter />
    </div>
  );
}
